import { useEffect } from "react";

const CSS = "\n/* ============================================================\n   WAYPOINT & Co. \u2014 AIR\n   Phase Six \u00b7 The Arrival\n   Motion language: vertical, atmospheric, precise.\n   ============================================================ */\n\n:root{\n  --ivory:        #F1EEE7;\n  --ivory-deep:   #E9E5DB;\n  --charcoal:     #211F1B;\n  --charcoal-soft:#2C2A25;\n  --cloud:        #D9D6CF;\n  --bluegrey:     #8B98A3;\n  --bluegrey-deep:#5E6B75;\n  --metal:        #B3B1AA;\n  --warm:         #A8845C;\n  --ink-on-dark:  #EDEAE2;\n  --ink-soft:     #6D6A62;\n\n  --serif: \"Instrument Serif\", Georgia, serif;\n  --sans:  \"Instrument Sans\", -apple-system, \"Helvetica Neue\", sans-serif;\n  --mono:  \"IBM Plex Mono\", \"SF Mono\", monospace;\n\n  --gutter: clamp(20px, 5vw, 72px);\n  --max: 1360px;\n  --ease: cubic-bezier(0.22, 1, 0.36, 1);\n}\n\n*{ margin:0; padding:0; box-sizing:border-box; }\nhtml{ scroll-behavior:smooth; }\nbody{\n  background: var(--ivory);\n  color: var(--charcoal);\n  font-family: var(--sans);\n  font-size: 16px;\n  line-height: 1.65;\n  -webkit-font-smoothing: antialiased;\n  overflow-x: hidden;\n}\n\n::selection{ background: var(--bluegrey); color: var(--ivory); }\n\na{ color: inherit; text-decoration: none; }\nbutton{ font: inherit; color: inherit; background: none; border: none; cursor: pointer; }\n\n/* ---------- shared vocabulary ---------- */\n\n.wrap{ max-width: var(--max); margin: 0 auto; padding-left: var(--gutter); padding-right: var(--gutter); }\n\n.eyebrow{\n  font-family: var(--mono);\n  font-size: 11px;\n  font-weight: 400;\n  letter-spacing: 0.32em;\n  text-transform: uppercase;\n  color: var(--bluegrey-deep);\n}\n.dark .eyebrow{ color: var(--bluegrey); }\n\n.display{\n  font-family: var(--serif);\n  font-weight: 400;\n  line-height: 1.06;\n  letter-spacing: -0.01em;\n}\n\n.lede{\n  font-size: clamp(17px, 1.35vw, 20px);\n  line-height: 1.75;\n  color: var(--ink-soft);\n  max-width: 58ch;\n}\n.dark .lede{ color: #B9B6AC; }\n\n.mono-note{\n  font-family: var(--mono);\n  font-size: 11.5px;\n  font-weight: 300;\n  letter-spacing: 0.08em;\n  line-height: 1.9;\n  color: var(--bluegrey-deep);\n}\n.dark .mono-note{ color: var(--bluegrey); }\n\n.hairline{ border: none; border-top: 1px solid var(--metal); opacity: .55; }\n\n/* actions */\n.action{\n  display: inline-flex; align-items: center; gap: 14px;\n  font-size: 13px; font-weight: 500;\n  letter-spacing: 0.18em; text-transform: uppercase;\n  padding: 17px 30px;\n  border: 1px solid var(--charcoal);\n  transition: background .45s var(--ease), color .45s var(--ease);\n}\n.action .tick{ font-family: var(--mono); font-weight: 300; transition: transform .45s var(--ease); }\n.action:hover{ background: var(--charcoal); color: var(--ivory); }\n.action:hover .tick{ transform: translateY(-3px); }\n.action.solid{ background: var(--charcoal); color: var(--ivory); }\n.action.solid:hover{ background: var(--bluegrey-deep); border-color: var(--bluegrey-deep); }\n.action.quiet{\n  border: none; padding: 6px 0;\n  border-bottom: 1px solid var(--metal);\n}\n.action.quiet:hover{ background: none; color: var(--bluegrey-deep); border-bottom-color: var(--bluegrey-deep); }\n.dark .action{ border-color: var(--ink-on-dark); color: var(--ink-on-dark); }\n.dark .action:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n\na:focus-visible, button:focus-visible, summary:focus-visible{\n  outline: 2px solid var(--bluegrey-deep);\n  outline-offset: 4px;\n}\n\n/* upward reveal */\n.rise{ opacity: 0; transform: translateY(34px); transition: opacity 1s var(--ease), transform 1.1s var(--ease); }\n.rise.in{ opacity: 1; transform: translateY(0); }\n.rise.d1{ transition-delay: .12s; }\n.rise.d2{ transition-delay: .24s; }\n.rise.d3{ transition-delay: .36s; }\n\n/* ============================================================\n   NAV\n   ============================================================ */\n.nav{\n  position: fixed; top: 0; left: 0; right: 0; z-index: 60;\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 22px var(--gutter);\n  transition: background .5s var(--ease), box-shadow .5s var(--ease), padding .5s var(--ease);\n}\n.nav.scrolled{\n  background: rgba(241,238,231,0.92);\n  backdrop-filter: blur(12px);\n  padding-top: 14px; padding-bottom: 14px;\n  box-shadow: 0 1px 0 rgba(33,31,27,0.08);\n}\n.nav .wordmark{\n  font-family: var(--serif); font-size: 19px; letter-spacing: 0.04em;\n}\n.nav .wordmark span{ font-family: var(--mono); font-size: 10px; letter-spacing: .3em; color: var(--bluegrey-deep); display:block; margin-top:1px; }\n.nav-links{ display: flex; gap: 34px; align-items: center; }\n.nav-links a{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .28em; text-transform: uppercase;\n  color: var(--ink-soft); padding-bottom: 3px; border-bottom: 1px solid transparent;\n  transition: color .3s, border-color .3s;\n}\n.nav-links a:hover{ color: var(--charcoal); }\n.nav-links a.current{ color: var(--charcoal); border-bottom-color: var(--charcoal); }\n.nav-begin{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .24em; text-transform: uppercase;\n  border: 1px solid var(--charcoal); padding: 10px 20px;\n  transition: background .4s var(--ease), color .4s var(--ease);\n}\n.nav-begin:hover{ background: var(--charcoal); color: var(--ivory); }\n.nav.on-dark:not(.scrolled){ color: var(--ink-on-dark); }\n.nav.on-dark:not(.scrolled) .nav-links a{ color: rgba(237,234,226,.7); }\n.nav.on-dark:not(.scrolled) .nav-links a:hover,\n.nav.on-dark:not(.scrolled) .nav-links a.current{ color: var(--ink-on-dark); border-bottom-color: var(--ink-on-dark); }\n.nav.on-dark:not(.scrolled) .nav-begin{ border-color: var(--ink-on-dark); }\n.nav.on-dark:not(.scrolled) .nav-begin:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n.nav.on-dark:not(.scrolled) .wordmark span{ color: var(--bluegrey); }\n\n/* ============================================================\n   1 \u00b7 HERO \u2014 THE ARRIVAL\n   Descending light. The route begins faintly here.\n   ============================================================ */\n.hero{\n  position: relative;\n  min-height: 100svh;\n  display: flex; flex-direction: column; justify-content: flex-end;\n  color: var(--ink-on-dark);\n  background:\n    linear-gradient(180deg,\n      #21252A 0%,\n      #2E3640 22%,\n      #55606A 44%,\n      #8D8F8A 62%,\n      #C4BBA9 78%,\n      #E4DCCB 92%,\n      #F1EEE7 100%);\n  overflow: hidden;\n}\n/* slow cloud strata */\n.hero .strata{\n  position: absolute; inset: 0; pointer-events: none;\n  background:\n    radial-gradient(120% 34% at 18% 30%, rgba(217,214,207,0.10), transparent 70%),\n    radial-gradient(140% 30% at 82% 48%, rgba(217,214,207,0.14), transparent 70%),\n    radial-gradient(160% 26% at 40% 66%, rgba(241,238,231,0.16), transparent 72%);\n  animation: drift 46s linear infinite alternate;\n}\n@keyframes drift{\n  from{ transform: translateX(-2.5%) translateY(0.4%); }\n  to{   transform: translateX(2.5%)  translateY(-0.4%); }\n}\n/* faint beginning of the plotted route */\n.hero-route{\n  position: absolute; left: 50%; top: 0; height: 100%; width: 1px;\n  transform: translateX(-0.5px);\n  background: linear-gradient(180deg, transparent 0%, rgba(237,234,226,0.0) 18%, rgba(237,234,226,0.35) 60%, rgba(139,152,163,0.6) 100%);\n}\n.hero-route::after{\n  content:\"\"; position:absolute; bottom: 12vh; left: 50%;\n  width: 7px; height: 7px; border: 1px solid rgba(237,234,226,.75); border-radius: 50%;\n  transform: translateX(-50%);\n  background: transparent;\n}\n.hero-inner{\n  position: relative; z-index: 2;\n  padding-bottom: clamp(56px, 9vh, 110px);\n}\n.hero h1{\n  font-size: clamp(46px, 7.4vw, 108px);\n  max-width: 12ch;\n  text-shadow: 0 1px 30px rgba(33,31,27,0.18);\n}\n.hero .lede{ color: rgba(237,234,226,0.82); margin-top: 26px; max-width: 46ch; }\n.hero-actions{ display: flex; gap: 18px; margin-top: 44px; flex-wrap: wrap; }\n.hero .action{ border-color: rgba(237,234,226,0.9); color: var(--ink-on-dark); }\n.hero .action:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n.hero .action.solid{ background: rgba(237,234,226,0.96); color: var(--charcoal); border-color: transparent; }\n.hero .action.solid:hover{ background: var(--ivory); }\n\n.hero-ident{\n  position: absolute; right: var(--gutter); bottom: clamp(56px, 9vh, 110px);\n  text-align: right; z-index: 2;\n  font-family: var(--mono); font-size: 11px; font-weight: 300;\n  letter-spacing: 0.3em; line-height: 2.3; color: rgba(237,234,226,0.66);\n}\n.hero-ident b{ font-weight: 400; color: rgba(237,234,226,0.95); letter-spacing: .34em; }\n\n/* page-load sequence */\n.hero .load{ opacity: 0; transform: translateY(28px); animation: rise-in 1.4s var(--ease) forwards; }\n.hero .load.l2{ animation-delay: .25s; }\n.hero .load.l3{ animation-delay: .5s; }\n.hero .load.l4{ animation-delay: .75s; }\n@keyframes rise-in{ to{ opacity:1; transform: translateY(0); } }\n\n/* ============================================================\n   2 \u00b7 EDITORIAL INTRODUCTION \u2014 architectural split\n   ============================================================ */\n.intro{ padding: clamp(90px, 13vh, 170px) 0 clamp(80px, 11vh, 150px); }\n.split{\n  display: grid; grid-template-columns: minmax(0, 1.05fr) minmax(0, 1fr);\n  gap: clamp(40px, 6vw, 110px); align-items: center;\n}\n.intro h2{ font-size: clamp(34px, 4.2vw, 62px); margin: 22px 0 30px; max-width: 15ch; }\n.intro .statement{\n  font-family: var(--serif); font-style: italic;\n  font-size: clamp(19px, 1.7vw, 24px); color: var(--bluegrey-deep);\n  margin-top: 34px; max-width: 34ch;\n}\n\n/* runway detail \u2014 precision, not excess */\n.runway-figure{ position: relative; }\n.runway-figure svg{ display:block; width: 100%; height: auto; }\n.runway-figure .fig-caption{\n  margin-top: 18px;\n  display:flex; justify-content: space-between; gap: 16px; flex-wrap: wrap;\n}\n\n/* ============================================================\n   3 \u00b7 THE PLOTTED ROUTE \u2014 AIR Waypoint Navigation System\n   The signature. A flight-planning document, editorially set.\n   ============================================================ */\n.route{ background: var(--ivory-deep); padding: clamp(90px, 13vh, 170px) 0; position: relative; }\n.route-head{ text-align:center; max-width: 640px; margin: 0 auto clamp(60px, 8vh, 110px); }\n.route-head h2{ font-size: clamp(32px, 3.8vw, 54px); margin-top: 20px; }\n\n.course{ position: relative; max-width: 620px; margin: 0 auto; }\n.course-line{\n  position: absolute; left: 50%; top: 0; bottom: 0; width: 1px;\n  transform: translateX(-0.5px); background: var(--metal);\n}\n.course-line .progress{\n  position:absolute; top:0; left:0; width:100%; height:0%;\n  background: var(--bluegrey-deep);\n  transition: height .2s linear;\n}\n.fix{\n  position: relative; text-align: center;\n  padding: 0 0 clamp(52px, 7vh, 84px);\n}\n.fix:last-child{ padding-bottom: 0; }\n.fix .node{\n  width: 9px; height: 9px; border-radius: 50%;\n  border: 1px solid var(--bluegrey-deep); background: var(--ivory-deep);\n  margin: 0 auto 20px; position: relative; z-index: 2;\n  transition: background .5s var(--ease);\n}\n.fix.in .node{ background: var(--bluegrey-deep); }\n.fix .fix-kind{\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .34em;\n  text-transform: uppercase; color: var(--bluegrey-deep); margin-bottom: 10px;\n}\n.fix .fix-name{ font-family: var(--serif); font-size: clamp(24px, 2.6vw, 34px); line-height: 1.15; }\n.fix .fix-meta{ margin-top: 10px; }\n.fix.stage .fix-name{ color: var(--bluegrey-deep); font-style: italic; }\n.course-footnote{ text-align:center; margin-top: clamp(48px, 6vh, 72px); }\n\n/* ============================================================\n   4 \u00b7 WAYS TO FLY \u2014 editorial chapters\n   ============================================================ */\n.ways{ padding: clamp(100px, 14vh, 180px) 0 0; }\n.ways-head{ max-width: 700px; margin-bottom: clamp(64px, 8vh, 110px); }\n.ways-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin-top: 20px; }\n\n.chapter{\n  display: grid; grid-template-columns: 220px minmax(0,1fr) minmax(0, 0.9fr);\n  gap: clamp(28px, 4vw, 70px);\n  padding: clamp(56px, 7vh, 88px) 0;\n  border-top: 1px solid var(--metal);\n  align-items: start;\n}\n.chapter:last-of-type{ border-bottom: 1px solid var(--metal); }\n.chapter .ch-ident{ position: sticky; top: 110px; }\n.chapter .ch-ident .code{\n  font-family: var(--mono); font-size: 12px; letter-spacing: .4em;\n  text-transform: uppercase; color: var(--charcoal);\n}\n.chapter .ch-ident .band{\n  margin-top: 18px; height: 88px; width: 100%;\n  position: relative; overflow: hidden;\n}\n.chapter .ch-ident .band::before{\n  content:\"\"; position:absolute; inset:0;\n  transform: translateY(12%); transition: transform 1.2s var(--ease);\n}\n.chapter.in .ch-ident .band::before{ transform: translateY(0); }\n.chapter[data-way=\"direct\"] .band::before{\n  background: linear-gradient(180deg, #4E5A64 0%, #8B98A3 60%, #C9C4B7 100%);\n}\n.chapter[data-way=\"remote\"] .band::before{\n  background: linear-gradient(180deg, #6A6C60 0%, #A39A82 55%, #D6CDB8 100%);\n}\n.chapter[data-way=\"international\"] .band::before{\n  background: linear-gradient(180deg, #2E3640 0%, #5E6B75 55%, #9AA5AD 100%);\n}\n.chapter[data-way=\"rotary\"] .band::before{\n  background: linear-gradient(180deg, #4D4A42 0%, #7C7466 55%, #B8AC93 100%);\n}\n.chapter h3{ font-family: var(--serif); font-weight: 400; font-size: clamp(28px, 3vw, 42px); line-height: 1.12; max-width: 16ch; }\n.chapter .ch-copy p{ color: var(--ink-soft); margin-top: 20px; max-width: 52ch; }\n.chapter .ch-links{ margin-top: 30px; display: flex; flex-direction: column; gap: 14px; align-items: flex-start; }\n.chapter .ch-detail{ padding-top: 8px; }\n.chapter .ch-detail .mono-note{ display:block; }\n\n/* ============================================================\n   5 \u00b7 MISSION-LED AIRCRAFT SELECTION\n   ============================================================ */\n.selection{ padding: clamp(100px, 14vh, 180px) 0; }\n.selection-head{ max-width: 720px; margin-bottom: clamp(56px, 7vh, 96px); }\n.selection-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin: 20px 0 26px; }\n\n.cat{ border-top: 1px solid var(--metal); }\n.cat:last-of-type{ border-bottom: 1px solid var(--metal); }\n.cat summary{\n  list-style: none; cursor: pointer;\n  display: grid; grid-template-columns: 56px minmax(0,1fr) minmax(0,1.2fr) 40px;\n  gap: clamp(18px, 3vw, 48px); align-items: baseline;\n  padding: clamp(26px, 3.4vh, 40px) 0;\n  transition: color .3s;\n}\n.cat summary::-webkit-details-marker{ display: none; }\n.cat summary:hover .cat-name{ color: var(--bluegrey-deep); }\n.cat .cat-index{ font-family: var(--mono); font-size: 11px; font-weight:300; letter-spacing:.2em; color: var(--bluegrey-deep); }\n.cat .cat-name{ font-family: var(--serif); font-size: clamp(24px, 2.6vw, 36px); line-height:1.1; transition: color .3s; }\n.cat .cat-suit{ font-size: 15px; color: var(--ink-soft); align-self: center; }\n.cat .cat-toggle{\n  font-family: var(--mono); font-size: 18px; font-weight: 300;\n  color: var(--bluegrey-deep); text-align: right; align-self: center;\n  transition: transform .5s var(--ease);\n}\n.cat[open] .cat-toggle{ transform: rotate(45deg); }\n.cat-body{\n  display: grid; grid-template-columns: repeat(3, minmax(0,1fr));\n  gap: clamp(24px, 3vw, 56px);\n  padding: 6px 0 clamp(36px, 4.5vh, 56px);\n  padding-left: calc(56px + clamp(18px, 3vw, 48px));\n}\n.cat-field .f-label{\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: var(--bluegrey-deep); margin-bottom: 8px;\n}\n.cat-field .f-value{ font-size: 15px; color: var(--charcoal); line-height: 1.6; }\n.cat-field.route .f-value{ font-family: var(--mono); font-size: 12.5px; font-weight: 300; letter-spacing: .06em; color: var(--bluegrey-deep); line-height: 2; }\n.cat-actions{\n  grid-column: 1 / -1; display: flex; align-items: center; gap: 28px; flex-wrap: wrap;\n  padding-top: 8px;\n}\n.cat-cms{\n  grid-column: 1 / -1;\n}\n.selection .attribution{\n  margin-top: clamp(48px, 6vh, 72px);\n  max-width: 640px;\n}\n.selection .attribution p{\n  font-size: 13.5px; line-height: 1.8; color: var(--ink-soft);\n  padding-top: 22px; border-top: 1px solid var(--metal);\n}\n\n/* ============================================================\n   6 \u00b7 HELICOPTER \u2014 BEYOND THE RUNWAY  (dark chapter)\n   ============================================================ */\n.dark{ background: var(--charcoal); color: var(--ink-on-dark); }\n.rotary{ padding: clamp(110px, 15vh, 190px) 0; position: relative; overflow: hidden; }\n.rotary::before{\n  content:\"\"; position:absolute; inset:0; pointer-events:none;\n  background:\n    radial-gradient(90% 50% at 80% 0%, rgba(139,152,163,0.10), transparent 65%),\n    radial-gradient(70% 45% at 10% 100%, rgba(168,132,92,0.07), transparent 60%);\n}\n.rotary .wrap{ position: relative; }\n.rotary h2{ font-size: clamp(34px, 4.4vw, 64px); margin: 22px 0 26px; max-width: 14ch; }\n.rotary-grid{\n  display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n  gap: clamp(48px, 7vw, 120px); align-items: start;\n  margin-top: clamp(40px, 5vh, 64px);\n}\n.rotary-uses{ display: grid; grid-template-columns: 1fr 1fr; gap: 14px 32px; margin-top: 34px; }\n.rotary-uses div{\n  font-size: 14.5px; color: #B9B6AC;\n  padding: 12px 0; border-bottom: 1px solid rgba(179,177,170,0.22);\n}\n.rotary .action{ margin-top: 44px; }\n\n/* the cinematic sequence \u2014 vertical course on dark */\n.seq{ position: relative; padding-left: 34px; }\n.seq::before{\n  content:\"\"; position:absolute; left: 4px; top: 8px; bottom: 8px; width: 1px;\n  background: linear-gradient(180deg, var(--bluegrey) 0%, rgba(139,152,163,0.25) 100%);\n}\n.seq .leg{ position: relative; padding-bottom: 42px; }\n.seq .leg:last-child{ padding-bottom: 0; }\n.seq .leg::before{\n  content:\"\"; position:absolute; left: -34px; top: 7px;\n  width: 9px; height: 9px; border-radius: 50%;\n  border: 1px solid var(--bluegrey); background: var(--charcoal);\n}\n.seq .leg-mode{\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .34em;\n  text-transform: uppercase; color: var(--bluegrey); margin-bottom: 8px;\n}\n.seq .leg-route{ font-family: var(--serif); font-size: clamp(21px, 2.1vw, 28px); line-height: 1.2; }\n.seq .leg-note{ margin-top: 8px; font-size: 13.5px; color: #99968D; max-width: 40ch; }\n\n/* ============================================================\n   7 \u00b7 CONNECTED DESTINATIONS\n   ============================================================ */\n.dests{ padding: clamp(100px, 14vh, 180px) 0; background: var(--ivory); }\n.dests-head{ max-width: 700px; margin-bottom: clamp(56px, 7vh, 90px); }\n.dests-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin-top: 20px; }\n.dest-list{ border-top: 1px solid var(--metal); }\n.dest{ border-bottom: 1px solid var(--metal); }\n.dest-row{\n  width: 100%; text-align: left;\n  display: grid; grid-template-columns: minmax(0,1fr) auto 40px;\n  gap: 24px; align-items: center;\n  padding: clamp(28px, 3.6vh, 44px) 0;\n}\n.dest-row .d-name{ font-family: var(--serif); font-size: clamp(28px, 3.4vw, 48px); transition: color .3s, transform .6s var(--ease); }\n.dest-row:hover .d-name{ color: var(--bluegrey-deep); transform: translateX(10px); }\n.dest-row .d-code{ font-family: var(--mono); font-size: 11px; letter-spacing: .3em; color: var(--bluegrey-deep); }\n.dest-row .d-toggle{ font-family: var(--mono); font-size: 18px; font-weight:300; color: var(--bluegrey-deep); text-align:right; transition: transform .5s var(--ease); }\n.dest.open .d-toggle{ transform: rotate(45deg); }\n.dest-panel{\n  display: grid; grid-template-rows: 0fr; transition: grid-template-rows .7s var(--ease);\n}\n.dest.open .dest-panel{ grid-template-rows: 1fr; }\n.dest-panel > div{ overflow: hidden; }\n.dest-panel-inner{\n  display: grid; grid-template-columns: repeat(3, minmax(0,1fr)) auto;\n  gap: clamp(24px, 3vw, 56px); align-items: start;\n  padding: 4px 0 clamp(36px, 4.5vh, 56px);\n}\n.dest-field .f-label{\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: var(--bluegrey-deep); margin-bottom: 10px;\n}\n.dest-field p{ font-size: 15px; color: var(--ink-soft); line-height: 1.7; max-width: 32ch; }\n.dest-field .journey-name{ font-family: var(--serif); font-style: italic; font-size: 19px; color: var(--charcoal); }\n.dest-go{ align-self: center; white-space: nowrap; }\n\n/* ============================================================\n   8 \u00b7 FEATURED AIR JOURNEYS\n   ============================================================ */\n.journeys{ background: var(--ivory-deep); padding: clamp(100px, 14vh, 180px) 0; }\n.journeys-head{ max-width: 700px; margin-bottom: clamp(56px, 7vh, 90px); }\n.journeys-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin-top: 20px; }\n.journey-grid{ display: grid; grid-template-columns: repeat(3, minmax(0,1fr)); gap: clamp(20px, 2.6vw, 40px); }\n.journey{\n  background: var(--ivory);\n  border: 1px solid rgba(179,177,170,0.6);\n  padding: clamp(28px, 3vw, 44px);\n  display: flex; flex-direction: column;\n  transition: transform .7s var(--ease), box-shadow .7s var(--ease);\n}\n.journey:hover{ transform: translateY(-8px); box-shadow: 0 24px 60px -30px rgba(33,31,27,0.28); }\n.journey .j-kicker{ margin-bottom: 22px; }\n.journey h3{ font-family: var(--serif); font-weight:400; font-size: clamp(24px, 2.2vw, 32px); line-height: 1.12; margin-bottom: 26px; }\n.j-course{ position: relative; padding-left: 24px; flex: 1; }\n.j-course::before{\n  content:\"\"; position:absolute; left:3px; top: 7px; bottom: 7px; width:1px; background: var(--metal);\n}\n.j-step{ position: relative; padding-bottom: 20px; }\n.j-step:last-child{ padding-bottom: 0; }\n.j-step::before{\n  content:\"\"; position:absolute; left:-24px; top: 6px;\n  width: 7px; height: 7px; border-radius: 50%;\n  border: 1px solid var(--bluegrey-deep); background: var(--ivory);\n}\n.j-step .s-kind{ font-family: var(--mono); font-size: 9.5px; letter-spacing: .3em; text-transform: uppercase; color: var(--bluegrey-deep); }\n.j-step .s-text{ font-size: 14.5px; margin-top: 3px; line-height: 1.55; }\n.journey .j-actions{\n  margin-top: 34px; padding-top: 24px; border-top: 1px solid rgba(179,177,170,0.5);\n  display: flex; flex-direction: column; gap: 12px; align-items: flex-start;\n}\n\n/* ============================================================\n   9 \u00b7 OPERATIONAL CONFIDENCE (dark)\n   ============================================================ */\n.confidence{ padding: clamp(110px, 15vh, 190px) 0; }\n.confidence h2{ font-size: clamp(34px, 4.4vw, 64px); margin: 22px 0 28px; max-width: 15ch; }\n.confidence .lede{ max-width: 52ch; }\n.principles{\n  display: grid; grid-template-columns: 1fr 1fr; gap: 1px;\n  background: rgba(179,177,170,0.25);\n  border: 1px solid rgba(179,177,170,0.25);\n  margin-top: clamp(56px, 7vh, 90px);\n}\n.principle{ background: var(--charcoal); padding: clamp(30px, 3.4vw, 52px); }\n.principle .p-code{\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .34em;\n  text-transform: uppercase; color: var(--bluegrey); margin-bottom: 20px;\n}\n.principle p{ font-family: var(--serif); font-size: clamp(19px, 1.8vw, 25px); line-height: 1.4; color: var(--ink-on-dark); max-width: 26ch; }\n.confidence .managed{\n  margin-top: clamp(48px, 6vh, 72px);\n  columns: 3; column-gap: 48px;\n  font-size: 13.5px; color: #99968D; line-height: 2.2;\n}\n.confidence .managed span{ display: block; break-inside: avoid; }\n\n/* ============================================================\n   10 \u00b7 BEGIN THE JOURNEY\n   ============================================================ */\n.begin{\n  padding: clamp(120px, 18vh, 220px) 0;\n  text-align: center;\n  background:\n    linear-gradient(180deg, var(--ivory) 0%, var(--ivory-deep) 100%);\n  position: relative; overflow: hidden;\n}\n.begin::before{\n  content:\"\"; position:absolute; left:50%; top:0; bottom: 46%; width:1px;\n  background: linear-gradient(180deg, var(--metal), transparent);\n  transform: translateX(-.5px);\n}\n.begin h2{ font-size: clamp(38px, 5.4vw, 84px); max-width: 14ch; margin: 24px auto 26px; }\n.begin .lede{ margin: 0 auto 46px; }\n.begin-actions{ display:flex; gap: 18px; justify-content: center; flex-wrap: wrap; }\n\n/* ============================================================\n   FOOTER\n   ============================================================ */\n.footer{ background: var(--charcoal); color: var(--ink-on-dark); padding: clamp(64px, 8vh, 100px) 0 40px; }\n.footer-top{\n  display: grid; grid-template-columns: minmax(0,1.4fr) repeat(3, minmax(0,1fr));\n  gap: clamp(32px, 4vw, 64px);\n  padding-bottom: clamp(44px, 5vh, 64px);\n  border-bottom: 1px solid rgba(179,177,170,0.22);\n}\n.footer .wordmark{ font-family: var(--serif); font-size: 22px; }\n.footer .wordmark span{ font-family: var(--mono); font-size: 10px; letter-spacing:.3em; color: var(--bluegrey); display:block; margin-top: 4px; }\n.footer h4{ font-family: var(--mono); font-size: 10.5px; font-weight: 400; letter-spacing: .32em; text-transform: uppercase; color: var(--bluegrey); margin-bottom: 20px; }\n.footer ul{ list-style: none; display: flex; flex-direction: column; gap: 12px; }\n.footer ul a{ font-size: 14px; color: #B9B6AC; transition: color .3s; }\n.footer ul a:hover{ color: var(--ink-on-dark); }\n.footer-bottom{\n  display: flex; justify-content: space-between; gap: 24px; flex-wrap: wrap;\n  padding-top: 32px;\n}\n.footer-bottom .mono-note{ color: #78766E; }\n\n/* ============================================================\n   ADD AIR TO JOURNEY \u2014 persistent quiet control\n   ============================================================ */\n.add-air{\n  position: fixed; right: 26px; bottom: 26px; z-index: 70;\n  display: inline-flex; align-items: center; gap: 12px;\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .26em; text-transform: uppercase;\n  background: rgba(241,238,231,0.94); backdrop-filter: blur(10px);\n  color: var(--charcoal);\n  border: 1px solid var(--metal);\n  padding: 13px 20px;\n  transition: background .4s var(--ease), color .4s var(--ease), border-color .4s var(--ease), transform .6s var(--ease);\n  opacity: 0; transform: translateY(16px); pointer-events: none;\n}\n.add-air.visible{ opacity: 1; transform: translateY(0); pointer-events: auto; }\n.add-air .dot{\n  width: 7px; height: 7px; border-radius: 50%;\n  border: 1px solid var(--bluegrey-deep); transition: background .4s;\n}\n.add-air:hover{ border-color: var(--charcoal); }\n.add-air.added{ background: var(--charcoal); color: var(--ivory); border-color: var(--charcoal); }\n.add-air.added .dot{ background: var(--bluegrey); border-color: var(--bluegrey); }\n\n/* ============================================================\n   REDUCED MOTION\n   ============================================================ */\n@media (prefers-reduced-motion: reduce){\n  html{ scroll-behavior: auto; }\n  *, *::before, *::after{ animation: none !important; transition: none !important; }\n  .rise{ opacity: 1; transform: none; }\n  .hero .load{ opacity: 1; transform: none; }\n  .course-line .progress{ height: 100% !important; }\n}\n\n/* ============================================================\n   MOBILE \u2014 vertical course log\n   ============================================================ */\n@media (max-width: 980px){\n  .split{ grid-template-columns: 1fr; }\n  .chapter{ grid-template-columns: 1fr; gap: 24px; }\n  .chapter .ch-ident{ position: static; display:flex; align-items:center; gap: 20px; }\n  .chapter .ch-ident .band{ margin-top: 0; height: 44px; flex: 1; }\n  .cat summary{ grid-template-columns: 40px minmax(0,1fr) 32px; }\n  .cat .cat-suit{ display: none; }\n  .cat-body{ grid-template-columns: 1fr; padding-left: 0; gap: 22px; }\n  .rotary-grid{ grid-template-columns: 1fr; }\n  .dest-panel-inner{ grid-template-columns: 1fr; gap: 22px; }\n  .journey-grid{ grid-template-columns: 1fr; }\n  .principles{ grid-template-columns: 1fr; }\n  .confidence .managed{ columns: 2; }\n  .footer-top{ grid-template-columns: 1fr 1fr; }\n  .hero-ident{ display: none; }\n  .nav-links{ display: none; }\n}\n@media (max-width: 560px){\n  .confidence .managed{ columns: 1; }\n  .footer-top{ grid-template-columns: 1fr; }\n  .rotary-uses{ grid-template-columns: 1fr; }\n  .add-air{ right: 16px; bottom: 16px; }\n}\n";
const HTML = "<!-- ============ NAV ============ -->\n<nav class=\"nav on-dark\" id=\"nav\">\n  <a href=\"/\" class=\"wordmark\">WAYPOINT &amp; Co.<span>SEA \u00b7 STAY \u00b7 AIR</span></a>\n  <div class=\"nav-links\">\n    <a href=\"/sea\">Sea</a>\n    <a href=\"/stay\">Stay</a>\n    <a href=\"/air\" class=\"current\" aria-current=\"page\">Air</a>\n    <a href=\"/journeys\">Journeys</a>\n  </div>\n  <a class=\"nav-begin\" href=\"/begin?mode=air&src=air-nav\">Begin</a>\n</nav>\n\n<!-- ============ 1 \u00b7 HERO \u2014 THE ARRIVAL ============ -->\n<header class=\"hero\" id=\"arrival\">\n  <div class=\"strata\" aria-hidden=\"true\"></div>\n  <div class=\"hero-route\" aria-hidden=\"true\"></div>\n\n  <div class=\"hero-inner wrap\">\n    <p class=\"eyebrow load\" style=\"color:rgba(237,234,226,.6)\">Phase of the journey \u00b7 The arrival</p>\n    <h1 class=\"display load l2\">Arrive on your own&nbsp;terms.</h1>\n    <p class=\"lede load l3\">Private fixed-wing and helicopter charter, selected and coordinated around the complete journey.</p>\n    <div class=\"hero-actions load l4\">\n      <a class=\"action solid\" href=\"/begin?mode=air&src=air-hero\">Plan a flight <span class=\"tick\">\u2191</span></a>\n      <a class=\"action\" href=\"#ways\">Explore private aviation <span class=\"tick\">\u2193</span></a>\n    </div>\n  </div>\n\n  <div class=\"hero-ident load l4\" aria-label=\"Air \u2014 private charter, Australia and international\">\n    <b>AIR</b><br>\n    PRIVATE CHARTER<br>\n    AUSTRALIA \u00b7 INTERNATIONAL\n  </div>\n</header>\n\n<!-- ============ 2 \u00b7 EDITORIAL INTRODUCTION ============ -->\n<section class=\"intro\">\n  <div class=\"wrap split\">\n    <div>\n      <p class=\"eyebrow rise\">Air</p>\n      <h2 class=\"display rise d1\">The journey begins before departure.</h2>\n      <p class=\"lede rise d2\">Private aviation is not defined by the aircraft alone. It is the coordination of timing, access, capability and destination into one considered movement.</p>\n      <p class=\"statement rise d3\">The right aircraft is the one that fits the journey.</p>\n    </div>\n\n    <!-- Precision detail: runway threshold & centreline, drawn, not stocked -->\n    <figure class=\"runway-figure rise d2\">\n      <svg viewBox=\"0 0 560 640\" role=\"img\" aria-label=\"Runway threshold markings viewed from above, annotated with heading and elevation\">\n        <defs>\n          <linearGradient id=\"rwy\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n            <stop offset=\"0\" stop-color=\"#2C2A25\"/>\n            <stop offset=\"1\" stop-color=\"#3A382F\"/>\n          </linearGradient>\n        </defs>\n        <rect x=\"60\" y=\"0\" width=\"440\" height=\"640\" fill=\"url(#rwy)\"/>\n        <!-- threshold piano keys -->\n        <g fill=\"#EDEAE2\" opacity=\"0.92\">\n          <rect x=\"92\"  y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"142\" y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"192\" y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"242\" y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"288\" y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"338\" y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"388\" y=\"512\" width=\"30\" height=\"96\"/>\n          <rect x=\"438\" y=\"512\" width=\"30\" height=\"96\"/>\n        </g>\n        <!-- designator -->\n        <text x=\"280\" y=\"452\" text-anchor=\"middle\" font-family=\"'IBM Plex Mono', monospace\" font-size=\"88\" font-weight=\"300\" fill=\"#EDEAE2\" opacity=\"0.9\">18</text>\n        <!-- centreline dashes -->\n        <g fill=\"#EDEAE2\" opacity=\"0.85\">\n          <rect x=\"272\" y=\"300\" width=\"16\" height=\"60\"/>\n          <rect x=\"272\" y=\"196\" width=\"16\" height=\"60\"/>\n          <rect x=\"272\" y=\"92\"  width=\"16\" height=\"60\"/>\n          <rect x=\"272\" y=\"0\"   width=\"16\" height=\"48\"/>\n        </g>\n        <!-- touchdown zone bars -->\n        <g fill=\"#EDEAE2\" opacity=\"0.55\">\n          <rect x=\"140\" y=\"230\" width=\"44\" height=\"14\"/>\n          <rect x=\"376\" y=\"230\" width=\"44\" height=\"14\"/>\n          <rect x=\"140\" y=\"130\" width=\"44\" height=\"14\"/>\n          <rect x=\"376\" y=\"130\" width=\"44\" height=\"14\"/>\n        </g>\n        <!-- edge lines -->\n        <rect x=\"76\" y=\"0\" width=\"4\" height=\"640\" fill=\"#EDEAE2\" opacity=\"0.4\"/>\n        <rect x=\"480\" y=\"0\" width=\"4\" height=\"640\" fill=\"#EDEAE2\" opacity=\"0.4\"/>\n        <!-- fine annotation ticks -->\n        <g stroke=\"#8B98A3\" stroke-width=\"1\" opacity=\"0.8\">\n          <line x1=\"20\" y1=\"512\" x2=\"52\" y2=\"512\"/>\n          <line x1=\"20\" y1=\"608\" x2=\"52\" y2=\"608\"/>\n          <line x1=\"36\" y1=\"512\" x2=\"36\" y2=\"608\"/>\n        </g>\n        <text x=\"14\" y=\"565\" font-family=\"'IBM Plex Mono', monospace\" font-size=\"11\" fill=\"#5E6B75\" transform=\"rotate(-90 14 565)\" letter-spacing=\"2\">THR</text>\n      </svg>\n      <figcaption class=\"fig-caption\">\n        <span class=\"mono-note\">RWY 18 \u00b7 HDG 184\u00b0M</span>\n        <span class=\"mono-note\">ELEV 15 FT \u00b7 SEALED</span>\n      </figcaption>\n    </figure>\n  </div>\n</section>\n\n<!-- ============ 3 \u00b7 THE PLOTTED ROUTE ============ -->\n<section class=\"route\" id=\"route\">\n  <div class=\"wrap\">\n    <div class=\"route-head\">\n      <p class=\"eyebrow rise\">The plotted route</p>\n      <h2 class=\"display rise d1\">One journey, held as a single course.</h2>\n    </div>\n\n    <div class=\"course\" id=\"course\">\n      <div class=\"course-line\" aria-hidden=\"true\"><div class=\"progress\" id=\"courseProgress\"></div></div>\n\n      <div class=\"fix rise\">\n        <div class=\"node\"></div>\n        <div class=\"fix-kind\">Depart</div>\n        <div class=\"fix-name\">Sunshine Coast</div>\n        <div class=\"fix-meta mono-note\">MCY \u00b7 26\u00b036\u2032S 153\u00b005\u2032E</div>\n      </div>\n\n      <div class=\"fix stage rise\">\n        <div class=\"node\"></div>\n        <div class=\"fix-kind\">Air</div>\n        <div class=\"fix-name\">Private fixed-wing</div>\n        <div class=\"fix-meta mono-note\">MCY \u2192 HTI \u00b7 \u2248 50 MINUTES<br>SUBJECT TO AIRCRAFT, WEATHER AND ROUTING</div>\n      </div>\n\n      <div class=\"fix rise\">\n        <div class=\"node\"></div>\n        <div class=\"fix-kind\">Arrive</div>\n        <div class=\"fix-name\">Hamilton Island</div>\n        <div class=\"fix-meta mono-note\">HTI \u00b7 20\u00b021\u2032S 148\u00b057\u2032E</div>\n      </div>\n\n      <div class=\"fix stage rise\">\n        <div class=\"node\"></div>\n        <div class=\"fix-kind\">Transfer</div>\n        <div class=\"fix-name\">Private vehicle</div>\n      </div>\n\n      <div class=\"fix rise\">\n        <div class=\"node\"></div>\n        <div class=\"fix-kind\">Stay</div>\n        <div class=\"fix-name\">Hamilton Island residence</div>\n      </div>\n\n      <div class=\"fix stage rise\">\n        <div class=\"node\"></div>\n        <div class=\"fix-kind\">Sea</div>\n        <div class=\"fix-name\">ALANI</div>\n        <div class=\"fix-meta mono-note\">THE COURSE CONTINUES</div>\n      </div>\n    </div>\n\n    <div class=\"course-footnote rise\">\n      <a class=\"action quiet\" href=\"/begin?dest=whitsundays&mode=air&src=air-route\">Shape this course <span class=\"tick\">\u2191</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 4 \u00b7 WAYS TO FLY ============ -->\n<section class=\"ways\" id=\"ways\">\n  <div class=\"wrap\">\n    <div class=\"ways-head\">\n      <p class=\"eyebrow rise\">Ways to fly</p>\n      <h2 class=\"display rise d1\">Four reasons the journey leaves the timetable behind.</h2>\n    </div>\n\n    <article class=\"chapter rise\" data-way=\"direct\">\n      <div class=\"ch-ident\">\n        <span class=\"code\">Direct</span>\n        <div class=\"band\" aria-hidden=\"true\"></div>\n      </div>\n      <div class=\"ch-copy\">\n        <h3>Move without the unnecessary connections.</h3>\n        <p>Depart when the day allows, not when the schedule dictates. Direct routing between the airports that suit the journey \u2014 regional, capital or remote \u2014 with the timing held to your calendar rather than the reverse.</p>\n        <div class=\"ch-links\">\n          <a class=\"action quiet\" href=\"/begin?mode=air&way=direct&src=air-ways\">Plan a direct flight <span class=\"tick\">\u2191</span></a>\n        </div>\n      </div>\n      <div class=\"ch-detail\">\n        <span class=\"mono-note\">SCHEDULE CONTROL<br>REGIONAL ACCESS<br>SINGLE MOVEMENT</span>\n      </div>\n    </article>\n\n    <article class=\"chapter rise\" data-way=\"remote\">\n      <div class=\"ch-ident\">\n        <span class=\"code\">Remote</span>\n        <div class=\"band\" aria-hidden=\"true\"></div>\n      </div>\n      <div class=\"ch-copy\">\n        <h3>Reach places the timetable does not.</h3>\n        <p>Regional airports, island strips, private properties and destinations beyond the reach of scheduled services. Aircraft and routing are assessed against the runway, the season and the conditions \u2014 so the remote arrival is as considered as the departure.</p>\n        <div class=\"ch-links\">\n          <a class=\"action quiet\" href=\"/begin?mode=air&way=remote&src=air-ways\">Reach further <span class=\"tick\">\u2191</span></a>\n        </div>\n      </div>\n      <div class=\"ch-detail\">\n        <span class=\"mono-note\">SHORT &amp; UNSEALED STRIPS<br>ISLAND ACCESS<br>PRIVATE PROPERTIES</span>\n      </div>\n    </article>\n\n    <article class=\"chapter rise\" data-way=\"international\">\n      <div class=\"ch-ident\">\n        <span class=\"code\">International</span>\n        <div class=\"band\" aria-hidden=\"true\"></div>\n      </div>\n      <div class=\"ch-copy\">\n        <h3>Cross borders with one coordinated journey.</h3>\n        <p>International charter arranged through appropriately authorised operators, with permits, ground handling, customs and onward movements coordinated as a single plan. One point of contact from first departure to final arrival.</p>\n        <div class=\"ch-links\">\n          <a class=\"action quiet\" href=\"/begin?mode=air&way=international&src=air-ways\">Plan an international journey <span class=\"tick\">\u2191</span></a>\n        </div>\n      </div>\n      <div class=\"ch-detail\">\n        <span class=\"mono-note\">PERMITS &amp; CLEARANCES<br>CIQ COORDINATION<br>ONWARD MOVEMENTS</span>\n      </div>\n    </article>\n\n    <article class=\"chapter rise\" data-way=\"rotary\">\n      <div class=\"ch-ident\">\n        <span class=\"code\">Rotary</span>\n        <div class=\"band\" aria-hidden=\"true\"></div>\n      </div>\n      <div class=\"ch-copy\">\n        <h3>Continue beyond the runway.</h3>\n        <p>Helicopter charter carries the journey past the point where fixed-wing ends \u2014 to the yacht, the residence, the event or the destination no runway reaches. The final minutes of a journey deserve the same precision as the first.</p>\n        <div class=\"ch-links\">\n          <a class=\"action quiet\" href=\"/begin?mode=rotary&src=air-ways\">Plan a helicopter journey <span class=\"tick\">\u2191</span></a>\n          <a class=\"action quiet\" href=\"#rotary\">See how rotary connects <span class=\"tick\">\u2193</span></a>\n        </div>\n      </div>\n      <div class=\"ch-detail\">\n        <span class=\"mono-note\">YACHT CONNECTIONS<br>RESIDENCE TRANSFERS<br>SCENIC &amp; REMOTE</span>\n      </div>\n    </article>\n  </div>\n</section>\n\n<!-- ============ 5 \u00b7 MISSION-LED AIRCRAFT SELECTION ============ -->\n<section class=\"selection\" id=\"selection\">\n  <div class=\"wrap\">\n    <div class=\"selection-head\">\n      <p class=\"eyebrow rise\">Aircraft</p>\n      <h2 class=\"display rise d1\">Selected for the journey.</h2>\n      <p class=\"lede rise d2\">Passenger numbers, luggage, distance, runway conditions and cabin requirements determine the right aircraft solution. The category below is the initial recommendation \u2014 a specific aircraft is subject to operator availability and mission review.</p>\n    </div>\n\n    <!-- CMS: aircraft categories render from `aircraft` schema.\n         Fields: commercialRelationship \u00b7 missionSuitability \u00b7 listingStatus \u00b7 availabilityMode\n         Exact specifications render only where verified. -->\n\n    <details class=\"cat rise\" data-cms=\"aircraft-category\" data-category=\"turboprop\">\n      <summary>\n        <span class=\"cat-index\">01</span>\n        <span class=\"cat-name\">Turboprop</span>\n        <span class=\"cat-suit\">Best suited to regional access, shorter strips and flexible sectors.</span>\n        <span class=\"cat-toggle\" aria-hidden=\"true\">+</span>\n      </summary>\n      <div class=\"cat-body\">\n        <div class=\"cat-field\"><div class=\"f-label\">Typical passengers</div><div class=\"f-value\">Up to nine, with soft luggage \u2014 small groups, families, working teams.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Typical journey</div><div class=\"f-value\">Regional and remote sectors, island access, multi-stop days.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Cabin character</div><div class=\"f-value\">Practical and quietly comfortable \u2014 built for access rather than display.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Access capability</div><div class=\"f-value\">Shorter, unsealed and remote strips beyond jet reach.</div></div>\n        <div class=\"cat-field route\"><div class=\"f-label\">Example route</div><div class=\"f-value\">SUNSHINE COAST \u2192 HAMILTON ISLAND<br>\u2248 50 MIN \u00b7 SUBJECT TO ROUTING</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Verified specifications</div><div class=\"f-value mono-note\" data-cms-bind=\"aircraft.specs\" data-render=\"verified-only\">RENDERED FROM VERIFIED CMS DATA</div></div>\n        <div class=\"cat-actions\"><a class=\"action quiet\" href=\"/begin?mode=air&category=turboprop&src=air-selection\">Enquire about turboprop journeys <span class=\"tick\">\u2191</span></a></div>\n      </div>\n    </details>\n\n    <details class=\"cat rise\" data-cms=\"aircraft-category\" data-category=\"light-jet\">\n      <summary>\n        <span class=\"cat-index\">02</span>\n        <span class=\"cat-name\">Light jet</span>\n        <span class=\"cat-suit\">Best suited to fast domestic sectors for smaller parties.</span>\n        <span class=\"cat-toggle\" aria-hidden=\"true\">+</span>\n      </summary>\n      <div class=\"cat-body\">\n        <div class=\"cat-field\"><div class=\"f-label\">Typical passengers</div><div class=\"f-value\">Four to six \u2014 executive pairs, couples, compact leisure groups.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Typical journey</div><div class=\"f-value\">Capital-to-capital, same-day returns, time-critical movements.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Cabin character</div><div class=\"f-value\">Efficient and private \u2014 a working or resting cabin for shorter sectors.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Access capability</div><div class=\"f-value\">Most sealed regional and capital-city airports.</div></div>\n        <div class=\"cat-field route\"><div class=\"f-label\">Example route</div><div class=\"f-value\">SUNSHINE COAST \u2192 SYDNEY<br>\u2248 1 HR 25 MIN \u00b7 SUBJECT TO ROUTING</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Verified specifications</div><div class=\"f-value mono-note\" data-cms-bind=\"aircraft.specs\" data-render=\"verified-only\">RENDERED FROM VERIFIED CMS DATA</div></div>\n        <div class=\"cat-actions\"><a class=\"action quiet\" href=\"/begin?mode=air&category=light-jet&src=air-selection\">Enquire about light jet journeys <span class=\"tick\">\u2191</span></a></div>\n      </div>\n    </details>\n\n    <details class=\"cat rise\" data-cms=\"aircraft-category\" data-category=\"midsize-jet\">\n      <summary>\n        <span class=\"cat-index\">03</span>\n        <span class=\"cat-name\">Midsize jet</span>\n        <span class=\"cat-suit\">Best suited to longer domestic and near-international sectors.</span>\n        <span class=\"cat-toggle\" aria-hidden=\"true\">+</span>\n      </summary>\n      <div class=\"cat-body\">\n        <div class=\"cat-field\"><div class=\"f-label\">Typical passengers</div><div class=\"f-value\">Six to eight, with generous luggage for extended stays.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Typical journey</div><div class=\"f-value\">East coast to Tasmania or the Top End; trans-Tasman by arrangement.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Cabin character</div><div class=\"f-value\">Stand-up cabin comfort \u2014 room to work, dine and rest en route.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Access capability</div><div class=\"f-value\">Sealed regional and international airports.</div></div>\n        <div class=\"cat-field route\"><div class=\"f-label\">Example route</div><div class=\"f-value\">BRISBANE \u2192 HOBART<br>\u2248 2 HR 45 MIN \u00b7 SUBJECT TO ROUTING</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Verified specifications</div><div class=\"f-value mono-note\" data-cms-bind=\"aircraft.specs\" data-render=\"verified-only\">RENDERED FROM VERIFIED CMS DATA</div></div>\n        <div class=\"cat-actions\"><a class=\"action quiet\" href=\"/begin?mode=air&category=midsize-jet&src=air-selection\">Enquire about midsize journeys <span class=\"tick\">\u2191</span></a></div>\n      </div>\n    </details>\n\n    <details class=\"cat rise\" data-cms=\"aircraft-category\" data-category=\"super-midsize-jet\">\n      <summary>\n        <span class=\"cat-index\">04</span>\n        <span class=\"cat-name\">Super-midsize jet</span>\n        <span class=\"cat-suit\">Best suited to longer range with larger parties and full luggage.</span>\n        <span class=\"cat-toggle\" aria-hidden=\"true\">+</span>\n      </summary>\n      <div class=\"cat-body\">\n        <div class=\"cat-field\"><div class=\"f-label\">Typical passengers</div><div class=\"f-value\">Eight to ten \u2014 extended families and larger leisure or working groups.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Typical journey</div><div class=\"f-value\">Long domestic sectors and South Pacific journeys in one movement.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Cabin character</div><div class=\"f-value\">A settled long-sector cabin \u2014 space, quiet and continuous comfort.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Access capability</div><div class=\"f-value\">Major domestic and international airports; performance for longer legs.</div></div>\n        <div class=\"cat-field route\"><div class=\"f-label\">Example route</div><div class=\"f-value\">SYDNEY \u2192 NADI<br>\u2248 4 HR \u00b7 SUBJECT TO ROUTING</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Verified specifications</div><div class=\"f-value mono-note\" data-cms-bind=\"aircraft.specs\" data-render=\"verified-only\">RENDERED FROM VERIFIED CMS DATA</div></div>\n        <div class=\"cat-actions\"><a class=\"action quiet\" href=\"/begin?mode=air&category=super-midsize-jet&src=air-selection\">Enquire about super-midsize journeys <span class=\"tick\">\u2191</span></a></div>\n      </div>\n    </details>\n\n    <details class=\"cat rise\" data-cms=\"aircraft-category\" data-category=\"heavy-long-range\">\n      <summary>\n        <span class=\"cat-index\">05</span>\n        <span class=\"cat-name\">Heavy &amp; long-range</span>\n        <span class=\"cat-suit\">Best suited to international journeys and intercontinental range.</span>\n        <span class=\"cat-toggle\" aria-hidden=\"true\">+</span>\n      </summary>\n      <div class=\"cat-body\">\n        <div class=\"cat-field\"><div class=\"f-label\">Typical passengers</div><div class=\"f-value\">Ten and above, with full luggage and crew rest for the longest sectors.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Typical journey</div><div class=\"f-value\">Australia to Asia, Europe or the Americas; complex multi-leg itineraries.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Cabin character</div><div class=\"f-value\">Distinct living zones \u2014 dining, working and sleeping across time zones.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Access capability</div><div class=\"f-value\">International gateways worldwide, with handling and permits coordinated.</div></div>\n        <div class=\"cat-field route\"><div class=\"f-label\">Example route</div><div class=\"f-value\">SYDNEY \u2192 SINGAPORE<br>\u2248 8 HR \u00b7 SUBJECT TO ROUTING</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Verified specifications</div><div class=\"f-value mono-note\" data-cms-bind=\"aircraft.specs\" data-render=\"verified-only\">RENDERED FROM VERIFIED CMS DATA</div></div>\n        <div class=\"cat-actions\"><a class=\"action quiet\" href=\"/begin?mode=air&category=heavy-long-range&src=air-selection\">Enquire about long-range journeys <span class=\"tick\">\u2191</span></a></div>\n      </div>\n    </details>\n\n    <details class=\"cat rise\" data-cms=\"aircraft-category\" data-category=\"helicopter\">\n      <summary>\n        <span class=\"cat-index\">06</span>\n        <span class=\"cat-name\">Helicopter</span>\n        <span class=\"cat-suit\">Best suited to transfers, scenic access and destinations without runways.</span>\n        <span class=\"cat-toggle\" aria-hidden=\"true\">+</span>\n      </summary>\n      <div class=\"cat-body\">\n        <div class=\"cat-field\"><div class=\"f-label\">Typical passengers</div><div class=\"f-value\">Two to six per aircraft, with light luggage; larger parties by multiple aircraft.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Typical journey</div><div class=\"f-value\">Airport to yacht or residence, island transfers, scenic and event arrivals.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Cabin character</div><div class=\"f-value\">Immediate and immersive \u2014 the landscape becomes part of the journey.</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Access capability</div><div class=\"f-value\">Helipads, vessels, beaches and cleared sites, subject to approval.</div></div>\n        <div class=\"cat-field route\"><div class=\"f-label\">Example route</div><div class=\"f-value\">HAMILTON ISLAND \u2192 WHITEHAVEN<br>\u2248 10 MIN \u00b7 SUBJECT TO CONDITIONS</div></div>\n        <div class=\"cat-field\"><div class=\"f-label\">Verified specifications</div><div class=\"f-value mono-note\" data-cms-bind=\"aircraft.specs\" data-render=\"verified-only\">RENDERED FROM VERIFIED CMS DATA</div></div>\n        <div class=\"cat-actions\"><a class=\"action quiet\" href=\"/begin?mode=rotary&src=air-selection\">Enquire about helicopter journeys <span class=\"tick\">\u2191</span></a></div>\n      </div>\n    </details>\n\n    <div class=\"attribution rise\">\n      <p>Aircraft are accessed through selected operators and trusted aviation partners. Final aircraft allocation is subject to mission requirements, regulatory considerations and availability.</p>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 6 \u00b7 HELICOPTER \u2014 BEYOND THE RUNWAY ============ -->\n<section class=\"dark rotary\" id=\"rotary\">\n  <div class=\"wrap\">\n    <p class=\"eyebrow rise\">Beyond the runway</p>\n    <h2 class=\"display rise d1\">Continue where fixed-wing ends.</h2>\n\n    <div class=\"rotary-grid\">\n      <div>\n        <p class=\"lede rise d2\">The runway is rarely the destination. Helicopter charter closes the final distance \u2014 carrying the journey from the apron to the deck, the residence, the ridgeline or the reef, as one continuous movement.</p>\n        <div class=\"rotary-uses rise d3\">\n          <div>Airport to yacht</div>\n          <div>Airport to residence</div>\n          <div>Scenic destination access</div>\n          <div>Island transfers</div>\n          <div>Remote dining</div>\n          <div>Event arrival</div>\n          <div>Wilderness experiences</div>\n          <div>Vessel repositioning</div>\n        </div>\n        <a class=\"action rise d3\" href=\"/begin?mode=rotary&src=air-rotary\">Plan a helicopter journey <span class=\"tick\">\u2191</span></a>\n      </div>\n\n      <!-- one strong cinematic sequence -->\n      <div class=\"seq rise d2\" aria-label=\"Example connected journey\">\n        <div class=\"leg\">\n          <div class=\"leg-mode\">Private aircraft</div>\n          <div class=\"leg-route\">Brisbane \u2192 Hamilton Island</div>\n          <div class=\"leg-note\">Fixed-wing charter into the Whitsundays, timed to the afternoon light.</div>\n        </div>\n        <div class=\"leg\">\n          <div class=\"leg-mode\">Helicopter</div>\n          <div class=\"leg-route\">Hamilton Island \u2192 Whitehaven</div>\n          <div class=\"leg-note\">A ten-minute transfer over the reef, landing where the sand meets the tide.</div>\n        </div>\n        <div class=\"leg\">\n          <div class=\"leg-mode\">Yacht</div>\n          <div class=\"leg-route\">Whitehaven \u2192 Hook Island</div>\n          <div class=\"leg-note\">The journey continues by sea \u2014 coordinated to the vessel's own timing.</div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 7 \u00b7 CONNECTED DESTINATIONS ============ -->\n<section class=\"dests\" id=\"destinations\">\n  <div class=\"wrap\">\n    <div class=\"dests-head\">\n      <p class=\"eyebrow rise\">Connected destinations</p>\n      <h2 class=\"display rise d1\">Where AIR joins the wider journey.</h2>\n    </div>\n\n    <!-- CMS: destinations & relationships render from the relationship graph.\n         Only CMS-authored relationships are rendered here. -->\n    <div class=\"dest-list rise\">\n\n      <div class=\"dest\" data-cms=\"destination\" data-dest=\"whitsundays\">\n        <button class=\"dest-row\" aria-expanded=\"false\">\n          <span class=\"d-name\">Whitsundays</span>\n          <span class=\"d-code\">HTI \u00b7 PPP</span>\n          <span class=\"d-toggle\" aria-hidden=\"true\">+</span>\n        </button>\n        <div class=\"dest-panel\"><div><div class=\"dest-panel-inner\">\n          <div class=\"dest-field\"><div class=\"f-label\">Arrive</div><p>Private fixed-wing to Hamilton Island or Proserpine.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Continue</div><p>Helicopter, private transfer, residence or yacht.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Suggested journey</div><p class=\"journey-name\">Island Passage</p></div>\n          <a class=\"action quiet dest-go\" href=\"/begin?dest=whitsundays&mode=air&src=air-dest\">Continue to the Whitsundays <span class=\"tick\">\u2191</span></a>\n        </div></div></div>\n      </div>\n\n      <div class=\"dest\" data-cms=\"destination\" data-dest=\"noosa\">\n        <button class=\"dest-row\" aria-expanded=\"false\">\n          <span class=\"d-name\">Noosa</span>\n          <span class=\"d-code\">MCY</span>\n          <span class=\"d-toggle\" aria-hidden=\"true\">+</span>\n        </button>\n        <div class=\"dest-panel\"><div><div class=\"dest-panel-inner\">\n          <div class=\"dest-field\"><div class=\"f-label\">Arrive</div><p>Private fixed-wing to Sunshine Coast, minutes from the river and the coast.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Continue</div><p>Private transfer to residence; day charters and coastal experiences by arrangement.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Suggested journey</div><p class=\"journey-name\">The Northern Light</p></div>\n          <a class=\"action quiet dest-go\" href=\"/begin?dest=noosa&mode=air&src=air-dest\">Continue to Noosa <span class=\"tick\">\u2191</span></a>\n        </div></div></div>\n      </div>\n\n      <div class=\"dest\" data-cms=\"destination\" data-dest=\"sydney\">\n        <button class=\"dest-row\" aria-expanded=\"false\">\n          <span class=\"d-name\">Sydney</span>\n          <span class=\"d-code\">SYD \u00b7 BWU</span>\n          <span class=\"d-toggle\" aria-hidden=\"true\">+</span>\n        </button>\n        <div class=\"dest-panel\"><div><div class=\"dest-panel-inner\">\n          <div class=\"dest-field\"><div class=\"f-label\">Arrive</div><p>Private fixed-wing to Sydney or Bankstown, timed around your commitments.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Continue</div><p>Private transfer, harbour charter or helicopter connection beyond the city.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Suggested journey</div><p class=\"journey-name\">Harbour Connection</p></div>\n          <a class=\"action quiet dest-go\" href=\"/begin?dest=sydney&mode=air&src=air-dest\">Continue to Sydney <span class=\"tick\">\u2191</span></a>\n        </div></div></div>\n      </div>\n\n      <div class=\"dest\" data-cms=\"destination\" data-dest=\"tasmania\">\n        <button class=\"dest-row\" aria-expanded=\"false\">\n          <span class=\"d-name\">Tasmania</span>\n          <span class=\"d-code\">HBA \u00b7 LST</span>\n          <span class=\"d-toggle\" aria-hidden=\"true\">+</span>\n        </button>\n        <div class=\"dest-panel\"><div><div class=\"dest-panel-inner\">\n          <div class=\"dest-field\"><div class=\"f-label\">Arrive</div><p>Private fixed-wing to Hobart or Launceston, crossing the strait in one sector.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Continue</div><p>Private residence, wilderness access, and the island's wine and produce country.</p></div>\n          <div class=\"dest-field\"><div class=\"f-label\">Suggested journey</div><p class=\"journey-name\">Southern Latitude</p></div>\n          <a class=\"action quiet dest-go\" href=\"/begin?dest=tasmania&mode=air&src=air-dest\">Continue to Tasmania <span class=\"tick\">\u2191</span></a>\n        </div></div></div>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============ 8 \u00b7 FEATURED AIR JOURNEYS ============ -->\n<section class=\"journeys\" id=\"journeys\">\n  <div class=\"wrap\">\n    <div class=\"journeys-head\">\n      <p class=\"eyebrow rise\">Air journeys</p>\n      <h2 class=\"display rise d1\">Journeys, not routes.</h2>\n    </div>\n\n    <div class=\"journey-grid\">\n\n      <article class=\"journey rise\" data-cms=\"journey\" data-journey=\"island-arrival\">\n        <div class=\"j-kicker eyebrow\">Journey 01</div>\n        <h3>Island Arrival</h3>\n        <div class=\"j-course\">\n          <div class=\"j-step\"><div class=\"s-kind\">Depart</div><div class=\"s-text\">Brisbane, mid-morning.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Air</div><div class=\"s-text\">Private fixed-wing to Hamilton Island.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Stay</div><div class=\"s-text\">Private residence above the passage.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Sea</div><div class=\"s-text\">Days aboard ALANI through the islands.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Return</div><div class=\"s-text\">A late-light sector home.</div></div>\n        </div>\n        <div class=\"j-actions\">\n          <a class=\"action quiet\" href=\"/begin?journey=island-arrival&src=air-journeys\">Explore the journey <span class=\"tick\">\u2191</span></a>\n          <a class=\"action quiet\" href=\"/begin?journey=island-arrival&shape=1&src=air-journeys\">Shape this journey <span class=\"tick\">\u2191</span></a>\n        </div>\n      </article>\n\n      <article class=\"journey rise d1\" data-cms=\"journey\" data-journey=\"southern-latitude\">\n        <div class=\"j-kicker eyebrow\">Journey 02</div>\n        <h3>Southern Latitude</h3>\n        <div class=\"j-course\">\n          <div class=\"j-step\"><div class=\"s-kind\">Depart</div><div class=\"s-text\">Melbourne, first light.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Air</div><div class=\"s-text\">Private fixed-wing across the strait to Tasmania.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Stay</div><div class=\"s-text\">A private residence in wine country.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Experience</div><div class=\"s-text\">Wilderness, cellar doors and the southern table.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Return</div><div class=\"s-text\">Northbound when the journey is complete.</div></div>\n        </div>\n        <div class=\"j-actions\">\n          <a class=\"action quiet\" href=\"/begin?journey=southern-latitude&src=air-journeys\">Explore the journey <span class=\"tick\">\u2191</span></a>\n          <a class=\"action quiet\" href=\"/begin?journey=southern-latitude&shape=1&src=air-journeys\">Shape this journey <span class=\"tick\">\u2191</span></a>\n        </div>\n      </article>\n\n      <article class=\"journey rise d2\" data-cms=\"journey\" data-journey=\"harbour-connection\">\n        <div class=\"j-kicker eyebrow\">Journey 03</div>\n        <h3>Harbour Connection</h3>\n        <div class=\"j-course\">\n          <div class=\"j-step\"><div class=\"s-kind\">Depart</div><div class=\"s-text\">Regional Australia, on your schedule.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Air</div><div class=\"s-text\">Private fixed-wing to Sydney.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Transfer</div><div class=\"s-text\">Private vehicle to the water's edge.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Sea</div><div class=\"s-text\">A harbour charter as the evening opens.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Return</div><div class=\"s-text\">Home the same night, or the morning after.</div></div>\n        </div>\n        <div class=\"j-actions\">\n          <a class=\"action quiet\" href=\"/begin?journey=harbour-connection&src=air-journeys\">Explore the journey <span class=\"tick\">\u2191</span></a>\n          <a class=\"action quiet\" href=\"/begin?journey=harbour-connection&shape=1&src=air-journeys\">Shape this journey <span class=\"tick\">\u2191</span></a>\n        </div>\n      </article>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============ 9 \u00b7 OPERATIONAL CONFIDENCE ============ -->\n<section class=\"dark confidence\" id=\"confidence\">\n  <div class=\"wrap\">\n    <p class=\"eyebrow rise\">Behind the movement</p>\n    <h2 class=\"display rise d1\">Precision is part of the experience.</h2>\n    <p class=\"lede rise d2\">Every journey carries a second, quieter itinerary \u2014 the one the passenger never needs to see. It is planned, checked and held from the first enquiry to the final arrival.</p>\n\n    <div class=\"principles\">\n      <div class=\"principle rise\">\n        <div class=\"p-code\">Fit for purpose</div>\n        <p>The aircraft is selected for the mission, not simply the image.</p>\n      </div>\n      <div class=\"principle rise d1\">\n        <div class=\"p-code\">Coordinated arrival</div>\n        <p>Flight, transfer, yacht and residence timings are treated as one movement.</p>\n      </div>\n      <div class=\"principle rise d2\">\n        <div class=\"p-code\">Trusted operators</div>\n        <p>Charters are arranged through appropriately authorised and selected aviation partners.</p>\n      </div>\n      <div class=\"principle rise d3\">\n        <div class=\"p-code\">Human oversight</div>\n        <p>Every journey is personally reviewed rather than automatically allocated.</p>\n      </div>\n    </div>\n\n    <div class=\"managed rise\" aria-label=\"Considerations managed behind the scenes\">\n      <span>Mission assessment</span>\n      <span>Operator and aircraft selection</span>\n      <span>Airport suitability</span>\n      <span>Passenger and luggage requirements</span>\n      <span>Ground handling</span>\n      <span>International permits and clearances</span>\n      <span>Customs and border coordination</span>\n      <span>Weather and routing considerations</span>\n      <span>Ground transfers</span>\n      <span>Yacht and residence timing</span>\n      <span>Itinerary monitoring</span>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 10 \u00b7 BEGIN THE JOURNEY ============ -->\n<section class=\"begin\" id=\"begin\">\n  <div class=\"wrap\">\n    <p class=\"eyebrow rise\">Begin</p>\n    <h2 class=\"display rise d1\">The course is waiting to be plotted.</h2>\n    <p class=\"lede rise d2\">Tell us where the journey should go. We will select and coordinate the rest.</p>\n    <div class=\"begin-actions rise d3\">\n      <a class=\"action solid\" href=\"/begin?mode=air&src=air-begin\">Plan a flight <span class=\"tick\">\u2191</span></a>\n      <a class=\"action\" href=\"/begin?mode=rotary&src=air-begin\">Plan a helicopter journey <span class=\"tick\">\u2191</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FOOTER ============ -->\n<footer class=\"footer dark\">\n  <div class=\"wrap\">\n    <div class=\"footer-top\">\n      <div>\n        <div class=\"wordmark\">WAYPOINT &amp; Co.<span>SEA \u00b7 STAY \u00b7 AIR</span></div>\n      </div>\n      <div>\n        <h4>Journey</h4>\n        <ul>\n          <li><a href=\"/sea\">Sea</a></li>\n          <li><a href=\"/stay\">Stay</a></li>\n          <li><a href=\"/air\">Air</a></li>\n          <li><a href=\"/journeys\">Journeys</a></li>\n        </ul>\n      </div>\n      <div>\n        <h4>Air</h4>\n        <ul>\n          <li><a href=\"#ways\">Ways to fly</a></li>\n          <li><a href=\"#selection\">Aircraft</a></li>\n          <li><a href=\"#rotary\">Helicopter</a></li>\n          <li><a href=\"#destinations\">Destinations</a></li>\n        </ul>\n      </div>\n      <div>\n        <h4>Company</h4>\n        <ul>\n          <li><a href=\"/about\">About</a></li>\n          <li><a href=\"/contact\">Contact</a></li>\n          <li><a href=\"/terms\">Terms</a></li>\n          <li><a href=\"/privacy\">Privacy</a></li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"footer-bottom\">\n      <span class=\"mono-note\">AIR \u00b7 PRIVATE CHARTER \u00b7 AUSTRALIA \u00b7 INTERNATIONAL</span>\n      <span class=\"mono-note\">\u00a9 WAYPOINT &amp; CO.</span>\n    </div>\n  </div>\n</footer>";
const JS = "(function(){\n  const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n\n  /* ---- nav state ---- */\n  const nav = document.getElementById('nav');\n  const onScrollNav = () => nav.classList.toggle('scrolled', window.scrollY > 40);\n  onScrollNav();\n  window.addEventListener('scroll', onScrollNav, { passive: true });\n\n  /* ---- upward reveals ---- */\n  const riseEls = document.querySelectorAll('.rise, .chapter, .fix');\n  if ('IntersectionObserver' in window && !reduced){\n    const io = new IntersectionObserver((entries) => {\n      entries.forEach(e => {\n        if (e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }\n      });\n    }, { threshold: 0.16, rootMargin: '0px 0px -6% 0px' });\n    riseEls.forEach(el => io.observe(el));\n  } else {\n    riseEls.forEach(el => el.classList.add('in'));\n  }\n\n  /* ---- plotted route: line draws with scroll ---- */\n  const course = document.getElementById('course');\n  const progress = document.getElementById('courseProgress');\n  if (course && progress && !reduced){\n    const drawCourse = () => {\n      const r = course.getBoundingClientRect();\n      const vh = window.innerHeight;\n      const start = vh * 0.82;\n      const total = r.height + (start - vh * 0.3);\n      const travelled = Math.min(Math.max(start - r.top, 0), total);\n      progress.style.height = (travelled / total * 100).toFixed(2) + '%';\n    };\n    drawCourse();\n    window.addEventListener('scroll', drawCourse, { passive: true });\n    window.addEventListener('resize', drawCourse);\n  }\n\n  /* ---- connected destinations: reveal panels ---- */\n  document.querySelectorAll('.dest').forEach(dest => {\n    const row = dest.querySelector('.dest-row');\n    row.addEventListener('click', () => {\n      const open = dest.classList.toggle('open');\n      row.setAttribute('aria-expanded', open ? 'true' : 'false');\n    });\n  });\n\n  /* ---- add AIR to journey (session state only) ---- */\n  const addAir = document.getElementById('addAir'); if(!addAir){return;}\n  const label = addAir.querySelector('.label');\n  let added = false; // joins the visitor's living plotted course via the Journey Engine session\n  const showFrom = () => addAir.classList.toggle('visible', window.scrollY > window.innerHeight * 0.7);\n  showFrom();\n  window.addEventListener('scroll', showFrom, { passive: true });\n  addAir.addEventListener('click', () => {\n    added = !added;\n    addAir.classList.toggle('added', added);\n    addAir.setAttribute('aria-pressed', added ? 'true' : 'false');\n    label.textContent = added ? 'AIR added to journey' : 'Add AIR to journey';\n    /* Journey Engine hook: window.WaypointJourney?.add({ mode: 'air', src: 'air-page' }) */\n  });\n})();";

export default function AirPage() {
  useEffect(() => {
    try { new Function(JS)(); } catch (e) { console.error("page script:", e); }
  }, []);
  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: CSS }} />
      <div dangerouslySetInnerHTML={{ __html: HTML }} />
    </>
  );
}
